const A = '/assets/library';

function sceneState(id, placeType, state, time, weather, tags = [], options = {}) {
  return {
    id: `scene_${id.replaceAll('-', '_')}`,
    src: `${A}/scenes/${id}.png`,
    eventType: options.eventType || 'story',
    sceneType: options.sceneType || 'wilderness',
    placeType,
    state,
    time,
    weather,
    themes: options.themes || ['fantasy'],
    tags: [placeType, state, time, weather, ...tags].filter(Boolean),
  };
}

function enemyAsset(id, tags = [], options = {}) {
  return {
    id: `enemy_${id.replaceAll('-', '_')}`,
    src: `${A}/enemies/${id}.png`,
    difficulty: options.difficulty,
    biome: options.biome,
    tags,
  };
}

function itemAsset(id, itemType, tags = [], options = {}) {
  return {
    id: `item_${id.replaceAll('-', '_')}`,
    src: `${A}/items/${id}.png`,
    itemType,
    biome: options.biome,
    tags,
  };
}

