function termsFor(entity = {}) {
  const raw = [
    entity.id, entity.name, entity.title, entity.description, entity.type,
    entity.itemType, entity.eventType, entity.sceneType, entity.difficulty,
    entity.gender, entity.age, entity.race, entity.class, entity.role, entity.themeKey, entity.biome,
    entity.importance, entity.faceDetail, entity.placeType, entity.state,
    entity.time, entity.weather,
    ...(entity.themes || []),
    ...(entity.tags || []),
  ].filter(Boolean).join(' ').toLowerCase();
  const terms = new Set((entity.tags || []).map(t => String(t).toLowerCase()));
  for (const [term, hints] of Object.entries(NAME_HINTS)) {
    if (hints.some(h => raw.includes(String(h).toLowerCase()))) terms.add(term);
  }
  for (const part of raw.split(/[^a-z0-9\u4e00-\u9fa5_-]+/).filter(Boolean)) terms.add(part);
  return terms;
}

function scoreAsset(asset, entity, category) {
  const terms = termsFor(entity);
  let score = 0;
  for (const tag of asset.tags || []) if (terms.has(String(tag).toLowerCase())) score += 3;
  if (asset.itemType && asset.itemType === entity.itemType) score += 4;
  if (asset.eventType && asset.eventType === entity.eventType) score += 4;
  if (asset.sceneType && asset.sceneType === entity.type) score += 6;
  if (asset.biome && terms.has(asset.biome)) score += 5;
  if (asset.difficulty && asset.difficulty === entity.difficulty) score += 3;
  if (asset.class && terms.has(asset.class)) score += 5;
  if (asset.role && terms.has(asset.role)) score += 5;
  if (asset.placeType && terms.has(asset.placeType)) score += 5;
  if (asset.state && terms.has(asset.state)) score += 4;
  if (asset.time && terms.has(asset.time)) score += 2;
  if (asset.weather && terms.has(asset.weather)) score += 2;
  if (asset.age && terms.has(asset.age)) score += 3;
  if (asset.gender && asset.gender !== 'unknown' && terms.has(asset.gender)) score += 2;
  if (asset.faceDetail && terms.has(asset.faceDetail)) score += 2;
  for (const theme of asset.themes || []) if (terms.has(String(theme).toLowerCase())) score += 2;
  if (entity.themeKey && asset.themes?.length) {
    score += asset.themes.includes(entity.themeKey) ? 4 : -6;
  }
  if (asset.race && terms.has(asset.race)) score += 2;

  if (category === 'characters' && score === 0) score = 1;
  if (category === 'enemies' && score === 0 && entity.difficulty === 'boss' && (asset.tags || []).includes('boss')) score = 1;
  return score;
}

function stableHash(value = '') {
  let hash = 2166136261;
  const text = String(value);
  for (let i = 0; i < text.length; i++) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function stableEntityKey(entity = {}) {
  return [
    entity.id,
    entity.name,
    entity.title,
    entity.role,
    entity.type,
    entity.itemType,
    ...(entity.tags || []),
  ].filter(Boolean).join('|') || 'asset';
}

export function selectAsset(entity, category) {
  const assets = PIXEL_ASSET_LIBRARY[category] || [];
  let bestScore = -1;
  let bestCandidates = [];
  for (const asset of assets) {
    const score = scoreAsset(asset, entity, category);
    if (score > bestScore) {
      bestScore = score;
      bestCandidates = [asset];
    } else if (score === bestScore && score > 0) {
      bestCandidates.push(asset);
    }
  }
  if (bestScore <= 0 || bestCandidates.length === 0) return null;
  const index = stableHash(stableEntityKey(entity)) % bestCandidates.length;
  return bestCandidates[index];
}

function assignListImages(list, category, overwrite) {
  return (list || []).map(card => {
    if (!overwrite && card.image) return card;
    const asset = selectAsset(card, category);
    return asset ? { ...card, image: asset.src } : card;
  });
}

export function assignPresetImages(preset, options = {}) {
  const overwrite = !!options.overwrite;
  const next = {
    ...preset,
    characters: assignListImages(preset.characters, 'characters', overwrite),
    enemies: assignListImages(preset.enemies, 'enemies', overwrite),
    items: assignListImages(preset.items, 'items', overwrite),
    events: assignListImages(preset.events, 'scenes', overwrite),
  };
  if (Array.isArray(preset.scenes)) {
    next.scenes = assignListImages(preset.scenes, 'scenes', overwrite);
  }
  return next;
}
